'use client';

import { useEffect } from 'react';

export default function Toast({
  message,
  onDismiss,
  duration = 3000,
}: {
  message: string;
  onDismiss: () => void;
  duration?: number;
}) {
  useEffect(() => {
    const t = setTimeout(onDismiss, duration);
    return () => clearTimeout(t);
  }, [duration, onDismiss]);

  return (
    <div
      className="fixed bottom-6 right-6 z-[100] bg-primary text-white px-4 py-3 rounded-lg shadow-lg"
      role="alert"
    >
      {message}
    </div>
  );
}
